export default class Lexer {
  #pos = 0;
  #ch;

  // テンプレート関連
  #inTemplate = false;
  #inTemplateExpr = false;
  #templateStack = [];
  #blocks = 0;

  // 正規表現文脈用
  #lastToken = null;
  #lastSignificantToken = null;

  static keywords = new Set([
    'const', 'let', 'var', 'function', 'return', 'if', 'else',
    'for', 'while', 'switch', 'case', 'break', 'continue',
    'class', 'extends', 'super', 'new', 'delete', 'typeof',
    'void', 'instanceof', 'in', 'this', 'throw', 'try', 'catch',
    'finally', 'import', 'export', 'yield', 'async', 'await', 'static', 'true', 'false', 'null', 'undefined'
  ]);

  constructor() {this.input=null}

  #next() {
    this.#pos++;
    this.#ch = this.input[this.#pos] ?? null;
  }

  #peek(n = 1) {
    return this.input[this.#pos + n] ?? null;
  }

  #readWhile(fn) {
    let str = '';
    while (this.#ch !== null && fn(this.#ch)) {
      str += this.#ch;
      this.#next();
    }
    return str;
  }

  #pushToken(tokens, token) {
    tokens.push(token);
    this.#lastToken = token;
    if (token.type !== 'whitespace' && token.type !== 'comment') {
      this.#lastSignificantToken = token;
    }
  }

  // whitespace
  #readWhitespace() {
    const value = this.#readWhile(ch => /\s/.test(ch));
    return { type: 'whitespace', value };
  }

  // コメント
  #readLineComment() {
    let value = '//';
    this.#next(); // /
    this.#next(); // /
    while (this.#ch !== null && this.#ch !== '\n') {
      value += this.#ch;
      this.#next();
    }
    return { type: 'comment', value };
  }

  #readBlockComment() {
    let value = '/*';
    this.#next(); // /
    this.#next(); // *
    while (this.#ch !== null) {
      if (this.#ch === '*' && this.#peek() === '/') {
        value += '*/';
        this.#next(); // *
        this.#next(); // /
        break;
      }
      value += this.#ch;
      this.#next();
    }
    return { type: 'comment', value };
  }

  // identifier
  #isIdentifierStart(ch) {
    return /[A-Za-z_$]/.test(ch);
  }

  #isIdentifierPart(ch) {
    return /[A-Za-z0-9_$]/.test(ch);
  }

  #readIdentifier() {
    const value = this.#readWhile(ch => this.#isIdentifierPart(ch));
    if (Lexer.keywords.has(value)) return { type: 'keyword', value };
    return { type: 'identifier', value };
  }

  #readString() {
    const quote = this.#ch;
    let value = quote;
    this.#next();
  
    while (this.#ch !== null) {
      if (this.#ch === '\\') {
        value += this.#ch;
        this.#next();
        if (this.#ch !== null || this.#ch === '\n') {
          value += this.#ch;
          this.#next();
        }
        continue;
      }
  
      if (this.#ch === quote) {
        value += quote;
        this.#next();
        return { type: 'string', value };
      }
  
      value += this.#ch;
      this.#next();
    }
  
    // ★ EOF に到達 → エラーとして返す
    return { type: 'error', value };
  }

  // template chunk
  #readTemplateChunk() {
    let value = '';
    while (this.#ch !== null) {
      if (this.#ch === '$' && this.#peek() === '{') break;
      if (this.#ch === '`') break;
      value += this.#ch;
      this.#next();
    }
    return { type: 'templatechunk', value };
  }

  // 正規表現が許される文脈か
  #isRegexAllowed() {
    const tok = this.#lastSignificantToken;
    if (!tok) return true;

    const t = tok.type;
    const v = tok.value;

    if (t === 'identifier' || t === 'number' || t === 'string') return false;
    if (t === 'regex') return false;
    if (t === 'punctuator' && (v === ')' || v === ']' || v === '}')) return false;

    return true;
  }

  // 正規表現リテラル
  #readRegex() {
    let value = '/';
    this.#next();
    let inClass = false;
  
    while (this.#ch !== null) {
      if (this.#ch === '\\') {
        value += this.#ch;
        this.#next();
        if (this.#ch !== null) {
          value += this.#ch;
          this.#next();
        }
        continue;
      }
  
      if (this.#ch === '[') {
        inClass = true;
        value += this.#ch;
        this.#next();
        continue;
      }
  
      if (this.#ch === ']' && inClass) {
        inClass = false;
        value += this.#ch;
        this.#next();
        continue;
      }
  
      if (this.#ch === '/' && !inClass) {
        value += '/';
        this.#next();
        break;
      }
  
      value += this.#ch;
      this.#next();
    }
  
    // ★ 正規表現が閉じていない
    if (this.#ch === null) {
      return { type: 'error', value };
    }
  
    // フラグ読み取り
    while (this.#ch !== null && /[a-z]/i.test(this.#ch)) {
      value += this.#ch;
      this.#next();
    }
  
    return { type: 'regex', value };
  }
  // punctuator（複数文字演算子対応）
  #readPunctuator() {
    const ch1 = this.#ch;
    const ch2 = ch1 + (this.#peek() ?? '');
    const ch3 = ch2 + (this.#peek(2) ?? '');

    const three = new Set(['===', '!==', '>>>', '<<=', '>>=', '**=']);
    if (three.has(ch3)) {
      this.#next(); this.#next(); this.#next();
      return { type: 'punctuator', value: ch3 };
    }

    const two = new Set([
      '==', '!=', '<=', '>=', '++', '--', '&&', '||', '??', '?.',
      '=>', '+=', '-=', '*=', '/=', '%=', '**', '<<', '>>',
      '&=', '|=', '^='
    ]);
    if (two.has(ch2)) {
      this.#next(); this.#next();
      return { type: 'punctuator', value: ch2 };
    }

    this.#next();
    return { type: 'punctuator', value: ch1 };
  }
  #readNumber() {
    let value = '';
  
    // 小数 .5
    if (this.#ch === '.') {
      value += '.';
      this.#next();
      if (!/[0-9]/.test(this.#ch)) {
        return { type: 'punctuator', value: '.' };
      }
      value += this.#readWhile(ch => /[0-9]/.test(ch));
      return this.#finishNumber(value);
    }
  
    // 0x, 0b, 0o
    if (this.#ch === '0') {
      value += '0';
      const next = this.#peek()?.toLowerCase();
  
      if (next === 'x') return this.#readRadixNumber(value, 16, /[0-9a-f]/i);
      if (next === 'b') return this.#readRadixNumber(value, 2, /[01]/);
      if (next === 'o') return this.#readRadixNumber(value, 8, /[0-7]/);
  
      this.#next();
      return this.#finishNumber(value + this.#readWhile(ch => /[0-9]/.test(ch)));
    }
  
    // 通常の10進
    value += this.#readWhile(ch => /[0-9]/.test(ch));
  
    // 小数
    if (this.#ch === '.') {
      value += '.';
      this.#next();
      value += this.#readWhile(ch => /[0-9]/.test(ch));
    }
  
    return this.#finishNumber(value);
  }
  
  #readRadixNumber(prefix, base, regex) {
    let value = prefix;
    this.#next(); // 0
    value += this.#ch; // x/b/o
    this.#next();
  
    const digits = this.#readWhile(ch => regex.test(ch));
    value += digits;
  
    // BigInt
    if (this.#ch === 'n') {
      value += 'n';
      this.#next();
      return { type: 'number', value };
    }
  
    return { type: 'number', value };
  }
  
  #finishNumber(value) {
    // 指数
    if (this.#ch === 'e' || this.#ch === 'E') {
      value += this.#ch;
      this.#next();
  
      if (this.#ch === '+' || this.#ch === '-') {
        value += this.#ch;
        this.#next();
      }
  
      value += this.#readWhile(ch => /[0-9]/.test(ch));
    }
  
    // BigInt
    if (this.#ch === 'n') {
      value += 'n';
      this.#next();
      return { type: 'number', value };
    }
  
    return { type: 'number', value };
  }
  tokenize(i) {
    this.input = i;
    this.#ch = i[0] ?? null;
    const tokens = [];
  
    while (this.#ch !== null) {
  
      // --- テンプレートモード ---
      if (this.#inTemplate) {
  
        // ${ 開始（テンプレート式開始）
        if (!this.#inTemplateExpr && this.#ch === '$' && this.#peek() === '{') {
          this.#inTemplateExpr = true;
          this.#blocks = 0;
          this.#next(); this.#next();
          this.#pushToken(tokens, { type: 'templateexprstart', value: '${' });
          continue;
        }
  
        // テンプレート式の中
        if (this.#inTemplateExpr) {
  
          // コメント
          if (this.#ch === '/' && this.#peek() === '/') {
            this.#pushToken(tokens, this.#readLineComment());
            continue;
          }
          if (this.#ch === '/' && this.#peek() === '*') {
            this.#pushToken(tokens, this.#readBlockComment());
            continue;
          }
  
          // 正規表現
          if (this.#ch === '/' && this.#isRegexAllowed()) {
            this.#pushToken(tokens, this.#readRegex());
            continue;
          }
  
          // ネストしたテンプレート開始: `${ `...` }`
          if (this.#ch === '`') {
            // 現在のテンプレ式状態をスタックに退避
            this.#templateStack.push({
              inTemplateExpr: this.#inTemplateExpr,
              blocks: this.#blocks
            });
            // 内側テンプレート本体モードへ
            this.#inTemplateExpr = false;
            this.#blocks = 0;
            this.#next();
            this.#pushToken(tokens, { type: 'templatestart', value: '`' });
            continue;
          }
  
          // ブロック { }
          if (this.#ch === '{') {
            this.#blocks++;
            this.#next();
            this.#pushToken(tokens, { type: 'punctuator', value: '{' });
            continue;
          }
          if (this.#ch === '}') {
            if (this.#blocks === 0) {
              // テンプレート式の終わり
              this.#inTemplateExpr = false;
              this.#next();
              this.#pushToken(tokens, { type: 'templateexprend', value: '}' });
              continue;
            }
            this.#blocks--;
            this.#next();
            this.#pushToken(tokens, { type: 'punctuator', value: '}' });
            continue;
          }
  
          // whitespace
          if (/\s/.test(this.#ch)) {
            this.#pushToken(tokens, this.#readWhitespace());
            continue;
          }
  
          // identifier / number / string / punctuator
          if (this.#isIdentifierStart(this.#ch)) {
            this.#pushToken(tokens, this.#readIdentifier());
            continue;
          }
          if (/[0-9]/.test(this.#ch) || (this.#ch === '.' && /[0-9]/.test(this.#peek()))) {
            this.#pushToken(tokens, this.#readNumber());
            continue;
          }
          if (this.#ch === '"' || this.#ch === "'") {
            this.#pushToken(tokens, this.#readString());
            continue;
          }
  
          this.#pushToken(tokens, this.#readPunctuator());
          continue;
        }
  
        // テンプレート文字列本体（式の外）
  
        // テンプレート終了 or ネストしたテンプレート終了
        if (this.#ch === '`') {
          this.#next();
          this.#pushToken(tokens, { type: 'templateend', value: '`' });
  
          if (this.#templateStack.length > 0) {
            // ネストしていた内側テンプレートの終了
            const state = this.#templateStack.pop();
            this.#inTemplateExpr = state.inTemplateExpr;
            this.#blocks = state.blocks;
            // まだ外側テンプレートの中なので this.#inTemplate は true のまま
          } else {
            // 最外のテンプレート終了
            this.#inTemplate = false;
          }
          continue;
        }
  
        // テンプレートチャンク
        this.#pushToken(tokens, this.#readTemplateChunk());
        continue;
      }
  
      // --- 通常モード ---
  
      // テンプレート開始（最外）
      if (this.#ch === '`') {
        this.#inTemplate = true;
        this.#inTemplateExpr = false;
        this.#blocks = 0;
        this.#next();
        this.#pushToken(tokens, { type: 'templatestart', value: '`' });
        continue;
      }
  
      // whitespace
      if (/\s/.test(this.#ch)) {
        this.#pushToken(tokens, this.#readWhitespace());
        continue;
      }
  
      // コメント
      if (this.#ch === '/' && this.#peek() === '/') {
        this.#pushToken(tokens, this.#readLineComment());
        continue;
      }
      if (this.#ch === '/' && this.#peek() === '*') {
        this.#pushToken(tokens, this.#readBlockComment());
        continue;
      }
  
      // 正規表現
      if (this.#ch === '/' && this.#isRegexAllowed()) {
        this.#pushToken(tokens, this.#readRegex());
        continue;
      }
  
      // identifier
      if (this.#isIdentifierStart(this.#ch)) {
        this.#pushToken(tokens, this.#readIdentifier());
        continue;
      }
  
      // 数値（10進・小数・基数・BigInt）
      if (/[0-9]/.test(this.#ch) || (this.#ch === '.' && /[0-9]/.test(this.#peek()))) {
        this.#pushToken(tokens, this.#readNumber());
        continue;
      }
  
      // string
      if (this.#ch === '"' || this.#ch === "'") {
        this.#pushToken(tokens, this.#readString());
        continue;
      }
  
      // punctuator
      this.#pushToken(tokens, this.#readPunctuator());
    }
  
    return tokens;
  }
}
